57	// runRecordToGQL converts a runRecord to the GraphQL Run type.
58	func runRecordToGQL(rec runRecord) *ddxgraphql.Run {
59		layer := ddxgraphql.RunLayerRun
60		switch strings.ToLower(rec.Layer) {
61		case "work":
62			layer = ddxgraphql.RunLayerWork
63		case "try":
64			layer = ddxgraphql.RunLayerTry
65		}
66	
67		run := &ddxgraphql.Run{
68			ID:          rec.ID,
69			Layer:       layer,
70			Status:      rec.Status,
71			ChildRunIds: rec.ChildRunIDs,
72		}
73		if run.ChildRunIds == nil {
74			run.ChildRunIds = []string{}
75		}
76		if rec.StartedAt != "" {
77			s := normalizeISOTime(rec.StartedAt)
78			run.StartedAt = &s
79		}
80		if rec.CompletedAt != "" {
81			s := normalizeISOTime(rec.CompletedAt)
82			run.CompletedAt = &s
83		}
84		if rec.BeadID != "" {
85			run.BeadID = &rec.BeadID
86		}
87		if rec.ArtifactID != "" {
88			run.ArtifactID = &rec.ArtifactID
89		}
90		if rec.ParentRunID != "" {
91			run.ParentRunID = &rec.ParentRunID
92		}
93	
94		switch layer {
95		case ddxgraphql.RunLayerWork:
96			if len(rec.QueueInputs) > 0 {
97				s := string(rec.QueueInputs)
98				run.QueueInputs = &s
99			}
100			if rec.StopCondition != "" {
101				run.StopCondition = &rec.StopCondition
102			}
103			if len(rec.SelectedBeadIDs) > 0 {
104				run.SelectedBeadIds = rec.SelectedBeadIDs
105			}
106		case ddxgraphql.RunLayerTry:
107			if rec.BaseRevision != "" {
108				run.BaseRevision = &rec.BaseRevision
109			}
110			if rec.ResultRevision != "" {
111				run.ResultRevision = &rec.ResultRevision
112			}
113			if rec.WorktreePath != "" {
114				run.WorktreePath = &rec.WorktreePath
115			}
116			if rec.MergeOutcome != "" {
117				run.MergeOutcome = &rec.MergeOutcome
118			}
119			if len(rec.CheckResults) > 0 {
120				s := string(rec.CheckResults)
121				run.CheckResults = &s
122			}
123		case ddxgraphql.RunLayerRun:
124			if rec.PromptSummary != "" {
125				run.PromptSummary = &rec.PromptSummary
126			}
127			if rec.PowerMin > 0 {
128				run.PowerMin = &rec.PowerMin
129			}
130			if rec.PowerMax > 0 {
131				run.PowerMax = &rec.PowerMax
132			}
133			if rec.Harness != "" {
134				run.Harness = &rec.Harness
135			}
136			if rec.Provider != "" {
137				run.Provider = &rec.Provider
138			}
139			if rec.Model != "" {
140				run.Model = &rec.Model
141			}
142			if rec.TokensIn > 0 {
143				run.TokensIn = &rec.TokensIn
144			}
145			if rec.TokensOut > 0 {
146				run.TokensOut = &rec.TokensOut
147			}
148			if rec.CostUSD != 0 {
149				run.CostUsd = &rec.CostUSD
