73		// Apply .ddx/config.yaml workers.default_spec + enforce workers.max_count
74		// (ddx-b6cf025c). The max_count cap counts currently-running drain workers
75		// for this project so the "+ Add worker" button can refuse cleanly.
76		if wc := loadWorkersConfig(projectRoot); wc != nil {
77			if defaultSpec := wc.DefaultSpec; defaultSpec != nil {
