package agent

import (
	"os"
	"path/filepath"
	"regexp"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestVocabConsistency_AttemptIDOnly asserts that cli/internal/agent/ and
// cli/internal/bead/ contain no legacy runID or run-id identifiers. The
// canonical term is attemptID / attempt_id / AttemptID.
func TestVocabConsistency_AttemptIDOnly(t *testing.T) {
	forbidden := regexp.MustCompile(`\brunID\b|run-id`)
	dirs := []string{
		filepath.Join("..", "agent"),
		filepath.Join("..", "bead"),
	}
	for _, dir := range dirs {
		entries, err := os.ReadDir(dir)
		if err != nil {
			t.Fatalf("ReadDir %s: %v", dir, err)
		}
		for _, e := range entries {
			if e.IsDir() || filepath.Ext(e.Name()) != ".go" {
				continue
			}
			path := filepath.Join(dir, e.Name())
			data, err := os.ReadFile(path)
			if err != nil {
				t.Fatalf("ReadFile %s: %v", path, err)
			}
			if m := forbidden.FindIndex(data); m != nil {
				t.Errorf("%s: forbidden legacy identifier %q at byte %d (rename to attemptID/attempt-id)",
					path, data[m[0]:m[1]], m[0])
			}
		}
	}
}

// TestExecutionDirs_AcceptBothNames verifies that the execution cleanup
// manager scans evidence directories regardless of naming convention (new
// attempt-id format or legacy run-id format), and that reading an exec
// manifest written with the legacy "run_id" JSON key still populates
// AttemptID via the backward-compat UnmarshalJSON on RunManifest.
func TestExecutionDirs_AcceptBothNames(t *testing.T) {
	root := t.TempDir()

	newDir := filepath.Join(root, ExecuteBeadArtifactDir, "20260508T000000-aabbccdd")
	require.NoError(t, os.MkdirAll(newDir, 0o755))
	require.NoError(t, os.WriteFile(
		filepath.Join(newDir, "manifest.json"),
		[]byte(`{"attempt_id":"20260508T000000-aabbccdd"}`), 0o644))
	require.NoError(t, os.WriteFile(
		filepath.Join(newDir, "result.json"),
		[]byte(`{"status":"success"}`), 0o644))

	legacyDir := filepath.Join(root, ExecuteBeadArtifactDir, "run-legacy-exec-attempt")
	require.NoError(t, os.MkdirAll(legacyDir, 0o755))
	require.NoError(t, os.WriteFile(
		filepath.Join(legacyDir, "manifest.json"),
		[]byte(`{"attempt_id":"run-legacy-exec-attempt"}`), 0o644))
	require.NoError(t, os.WriteFile(
		filepath.Join(legacyDir, "result.json"),
		[]byte(`{"status":"success"}`), 0o644))

	var summary ExecutionCleanupSummary
	n := scanCompleteEvidenceDirs(root, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
	assert.Equal(t, 2, n, "cleanup scanner must count both attempt-id and run-id named dirs")
}

