// TestExecutionDirs_AcceptBothNames verifies that RunManifest's UnmarshalJSON
// populates AttemptID from the legacy "run_id" key so old manifests on disk
// remain readable after the rename.
func TestExecutionDirs_AcceptBothNames(t *testing.T) {
	legacyJSON := `{"run_id":"exec-legacy@1","definition_id":"legacy-def@1","artifact_ids":["ART-1"],"status":"success","exit_code":0,"started_at":"2026-01-01T00:00:00Z","finished_at":"2026-01-01T00:00:01Z"}`
	newJSON := `{"attempt_id":"exec-new@1","definition_id":"new-def@1","artifact_ids":["ART-2"],"status":"success","exit_code":0,"started_at":"2026-01-02T00:00:00Z","finished_at":"2026-01-02T00:00:01Z"}`

	var legacyManifest RunManifest
	if err := json.Unmarshal([]byte(legacyJSON), &legacyManifest); err != nil {
		t.Fatalf("unmarshal legacy manifest: %v", err)
	}
	if legacyManifest.AttemptID != "exec-legacy@1" {
		t.Errorf("legacy manifest: AttemptID=%q, want exec-legacy@1 (populated from run_id)", legacyManifest.AttemptID)
	}

	var newManifest RunManifest
	if err := json.Unmarshal([]byte(newJSON), &newManifest); err != nil {
		t.Fatalf("unmarshal new manifest: %v", err)
	}
	if newManifest.AttemptID != "exec-new@1" {
		t.Errorf("new manifest: AttemptID=%q, want exec-new@1", newManifest.AttemptID)
	}
}

